import{_ as t,o,c as a,a3 as s}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"101. Designated Work Groups","description":"","frontmatter":{"title":"101. Designated Work Groups","eba":"Allied Health Professionals 2021-2026","topics":["consultation","union-matters","ohs"]},"headers":[],"relativePath":"ebas/allied-health/ohs/101-designated-work-groups.md","filePath":"ebas/allied-health/ohs/101-designated-work-groups.md"}'),n={name:"ebas/allied-health/ohs/101-designated-work-groups.md"};function r(i,e,d,l,p,c){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="_101-designated-work-groups" tabindex="-1">101. Designated Work Groups <a class="header-anchor" href="#_101-designated-work-groups" aria-label="Permalink to &quot;101. Designated Work Groups&quot;">​</a></h1><p><strong>101.1</strong> Where Union members constitute the majority of the workforce within a designated work group, the Employer will establish and maintain a system of DWGs in consultation with Employees and the Union.</p><p><strong>101.2</strong> In determining the particulars of DWGs (including number of HSRs), the following considerations will, where practicable, be taken into account:</p><p><strong>(a)</strong> the specific needs, conditions and hazards affecting Employees in the area(s) concerned;</p><p><strong>(b)</strong> the working arrangements, including shiftwork, of Employees in the area(s) concerned;</p><p><strong>(c)</strong> the accessibility of health and safety representatives to Employees in the area(s) concerned; and</p><p><strong>(d)</strong> the geographical layout of the workplace.</p>',7)])])}const u=t(n,[["render",r]]);export{g as __pageData,u as default};
